settings.source:
function run(generoIA, tipoMidiaIA, generoDigitado, contextoUsuario) {

    const genIA = (generoIA || "").toLowerCase().trim();
    const midiaIA = (tipoMidiaIA || "").toLowerCase().trim();
    const genManual = (generoDigitado || "").toLowerCase().trim();
    const contexto = (contextoUsuario || "").toLowerCase().trim();


    const eSerie = midiaIA.includes("serie") || midiaIA.includes("série") || 
                   contexto.includes("serie") || contexto.includes("série");


    const busca = genManual || genIA || contexto || "acao";

    const catalogo = {
        terror: { nome: "Terror", filmes: ["The Conjuring", "The Exorcist", "Hereditary"], series: ["The Haunting of Hill House", "Slasher", "Bates Motel"] },
        acao: { nome: "Ação", filmes: ["John Wick", "Mad Max: Fury Road", "Gladiator"], series: ["The Boys", "Reacher", "Cobra Kai"] },
        comedia: { nome: "Comédia", filmes: ["As branquelas", "The Hangover", "Superbad"], series: ["The Office", "Brooklyn Nine-Nine", "Modern Family"] },
        suspense: { nome: "Suspense", filmes: ["Gone Girl", "Shutter Island", "Seven"], series: ["Mindhunter", "The Sinner", "You"] },
        drama: { nome: "Drama", filmes: ["The Whale", "Parasite", "The Green Mile"], series: ["Breaking Bad", "This Is Us", "Succession"] },
        romance: { nome: "Romance", filmes: ["About Time", "The Notebook", "Pride & Prejudice"], series: ["Bridgerton", "Outlander", "Normal People"] }
    };


    let chave = "acao"; 
    if (busca.includes("terror") || busca.includes("medo")) chave = "terror";
    else if (busca.includes("acao") || busca.includes("ação")) chave = "acao";
    else if (busca.includes("comedia") || busca.includes("comédia") || busca.includes("rir")) chave = "comedia";
    else if (busca.includes("suspense") || busca.includes("mistério")) chave = "suspense";
    else if (busca.includes("drama") || busca.includes("triste") || busca.includes("chorar")) chave = "drama";
    else if (busca.includes("romance") || busca.includes("amor")) chave = "romance";

    const dados = catalogo[chave];
    const titulos = eSerie ? dados.series : dados.filmes;

    return {
        generoFinal: dados.nome,
        tipoFinal: eSerie ? "série" : "filme",
        item1: titulos[0],
        item2: titulos[1],
        item3: titulos[2]
    };
}
